import React from 'react';
import { useNavigate } from 'react-router-dom';

const modules = [
  {
    to:      '/trucks',
    label:   'Truck Management',
    desc:    'Trip entries, admin view, freight rates & settings',
    accent:  '#166534',
    status:  'Active',
  },
  {
    to:      '/scrap',
    label:   'Scrap Management',
    desc:    'Collected vs sold, running stock, monthly summary',
    accent:  '#0369a1',
    status:  'Coming Soon',
  },
  {
    to:      '/diesel',
    label:   'Diesel Inventory',
    desc:    'Purchase log, trip consumption, low-stock alerts',
    accent:  '#b45309',
    status:  'Coming Soon',
  },
  {
    to:      '/dashboard',
    label:   'Dashboard & Insights',
    desc:    'Revenue, expenses, per-truck KPIs, trend charts',
    accent:  '#4f46e5',
    status:  'Coming Soon',
  },
  {
    to:      '/drivers',
    label:   'Driver Advances',
    desc:    'Cash advances, expense claims, balance per driver',
    accent:  '#0f766e',
    status:  'Coming Soon',
  },
  {
    to:      '/maintenance',
    label:   'Maintenance Log',
    desc:    'Service history, next service due, parts & cost',
    accent:  '#9333ea',
    status:  'Coming Soon',
  },
  {
    to:      '/customers',
    label:   'Customer Ledger',
    desc:    'Outstanding freight, payment records, balance sheet',
    accent:  '#be123c',
    status:  'Coming Soon',
  },
];

const quickActions = [
  { label: 'New Trip Entry',  to: '/trucks',  },
  { label: 'Add Diesel',      to: '/diesel',  },
  { label: 'Log Scrap',       to: '/scrap',   },
];

export default function HomePage() {
  const navigate = useNavigate();

  return (
    <div>
      {/* Page heading */}
      <div style={s.heading}>
        <div>
          <div style={s.headTitle}>Operations Overview</div>
          <div style={s.headSub}>Select a module to get started</div>
        </div>
        <div style={s.qaRow}>
          {quickActions.map(a => (
            <button key={a.to} onClick={() => navigate(a.to)} style={s.qaBtn}>
              + {a.label}
            </button>
          ))}
        </div>
      </div>

      {/* Module grid */}
      <div style={s.grid}>
        {modules.map(m => (
          <div
            key={m.to}
            style={s.card}
            onClick={() => navigate(m.to)}
            onMouseEnter={e => e.currentTarget.style.boxShadow = '0 4px 20px rgba(0,0,0,0.10)'}
            onMouseLeave={e => e.currentTarget.style.boxShadow = '0 1px 4px rgba(0,0,0,0.06)'}
          >
            <div style={{ ...s.cardBar, background: m.accent }} />
            <div style={s.cardInner}>
              <div style={s.cardTop}>
                <div style={s.cardLabel}>{m.label}</div>
                <span style={{ ...s.badge, ...(m.status === 'Active' ? s.badgeActive : s.badgePending) }}>
                  {m.status}
                </span>
              </div>
              <div style={s.cardDesc}>{m.desc}</div>
              <div style={{ ...s.cardLink, color: m.accent }}>Open module →</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const s = {
  heading:     { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28, flexWrap: 'wrap', gap: 16 },
  headTitle:   { fontSize: 22, fontWeight: 700, color: '#0f2542' },
  headSub:     { fontSize: 13, color: '#94a3b8', marginTop: 3 },

  qaRow:       { display: 'flex', gap: 10, flexWrap: 'wrap' },
  qaBtn:       { padding: '9px 18px', background: '#0f2542', color: '#fff', border: 'none', borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: 'pointer', letterSpacing: '0.01em' },

  grid:        { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(290px, 1fr))', gap: 16 },

  card:        { background: '#fff', borderRadius: 10, boxShadow: '0 1px 4px rgba(0,0,0,0.06)', cursor: 'pointer', overflow: 'hidden', transition: 'box-shadow 0.2s', display: 'flex', flexDirection: 'column' },
  cardBar:     { height: 4 },
  cardInner:   { padding: '18px 20px 20px', display: 'flex', flexDirection: 'column', gap: 8, flex: 1 },
  cardTop:     { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  cardLabel:   { fontSize: 14, fontWeight: 700, color: '#0f2542' },
  cardDesc:    { fontSize: 12, color: '#64748b', lineHeight: 1.6 },
  cardLink:    { fontSize: 12, fontWeight: 600, marginTop: 4 },

  badge:       { fontSize: 10, fontWeight: 700, padding: '3px 8px', borderRadius: 20, letterSpacing: '0.04em', textTransform: 'uppercase' },
  badgeActive: { background: '#dcfce7', color: '#166534' },
  badgePending:{ background: '#f1f5f9', color: '#94a3b8' },
};
